var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>성황청</color> 폐쇄지구 어느 폐건물","JPN":"<color=#ffd34c>聖皇庁</color>閉鎖地区のある廃墟","ENG":"<color=#ffd34c>Holy Curia</color> Closed off District, in an abandoned building","TWN":"<color=#ffd34c>聖皇廳</color>封鎖區某個廢棄建築","SCN":"<color=#ffd34c>圣廷</color>封闭地区 某废弃建筑","DEU":"<color=#ffd34c>Holy Curia</color> Closed off District, in an abandoned building","FRA":"<color=#ffd34c>Holy Curia</color> Closed off District, in an abandoned building"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"17년 만인가……. 이곳도 오래간만이로군.","JPN":"17年ぶりか……久しいな。","ENG":"It's been a long time since I was last here... What was it? 17 years?","TWN":"時隔17年……好久沒來這裡了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 경과의 마지막 결투를 벌였던 곳.","JPN":"バーネット卿との最後の決闘の場所。","ENG":"The place where I had my last battle with Sir Burnett.","TWN":"這裡是與伯內特卿展開最後決鬥的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그래. 이곳 이름이…… <color=#ffd34c>로젠탈</color>이라고 했던가?","JPN":"そう、ここは……<color=#ffd34c>ローゼンタール</color>と言ったか。","ENG":"Yes. What was the name...? <color=#ffd34c>Rosenthal</color>, was it?","TWN":"沒錯，這地方好像是叫<color=#ffd34c>羅森泰</color>？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님. 미미하지만, 감지기에 신호가 잡히기 시작했습니다.","JPN":"学部長、わずかですが感知器が信号を捉えました。","ENG":"Sir. It's weak, but the detector has started to pick up on a signal.","TWN":"院長，雖然很微弱，但是感應器開始捕捉到訊號了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"틀림없습니다. 이곳은 과거 균열에 의해 차원 계면이 손상되었던 곳입니다.","JPN":"間違いありません。ここは過去、亀裂によって次元界面が損傷した場所です。","ENG":"I'm positive. This place has been damaged in the past by the rift.","TWN":"絕對沒錯。這裡就是次元裂縫過去因裂縫而受損的地方。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"……아아, 역시 그렇군.","JPN":"……ああ、やはりそうだったか。","ENG":"...Ah, I knew it.","TWN":"……啊，果然如此。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 그날…… 아이들이 사라졌던 건, 결투로 인해 발생한 차원 균열 때문이었나?","JPN":"あの日……子どもたちが消えたのは、決闘による次元亀裂のせいだったのだな。","ENG":"So that day... the children must've disappeared because of the dimensional rift created by the battle.","TWN":"那天……孩子們消失，果真是因為決鬥引起的次元裂縫？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오보에를 준비하게.","JPN":"オーボエを用意してくれ。","ENG":"Prepare the oboe.","TWN":"準備好雙簧管。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"17년 전, 균열이 발생했던 이곳에서…… 또 한 번 차원 균열을 발생시키는 거야.","JPN":"17年前、亀裂が発生したこの場所で……もう一度、次元の亀裂を発生させるのだ。","ENG":"I am going to create another rift... in the same place where one occurred 17 years ago.","TWN":"17年前，在曾出現裂縫的這個地方……再次製造次元裂縫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그리하면 마침내…… 우리가 그토록 찾아 헤매던, 성배에 다다를 수 있을 테니까.","JPN":"そうすればついに……我々が探し求めていた聖杯に辿り着けるだろう。","ENG":"Then finally... I will be able to reach the Holy Grail we've been searching for so long.","TWN":"那麼最終……就可以到達我們苦苦找尋的聖杯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"나 참. 누가 그걸 지켜보고 있을 거 같아?","JPN":"ふざけるな。そんなことさせるものか。","ENG":"Blimey. You think we're just gonna stand back and watch?","TWN":"喔？那麼你以為我們會袖手旁觀嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는……?","JPN":"君は……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"드디어 따라잡았다. 이 빌어먹을 늙다리!","JPN":"やっと追いついたぞ、このクソジジイ！","ENG":"Finally caught up with you, you old geezer!","TWN":"終於追上了，你這個老不死的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"이거 우연이로군. 아니, 어쩌면 필연인가.","JPN":"こんな偶然が……いや、必然かもしれないな。","ENG":"What a coincidence. Or should I say it's inevitable?","TWN":"呵呵，這是巧合嗎？還是說，這是必然？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 경과 마지막 결투를 나눈 곳에서 만난 사람이…… 하필, 자네일 줄이야.","JPN":"バーネット卿との最後の決闘の場で鉢合わせた者が……よりにもよって君だとは。","ENG":"The person I meet where I last fought Sir Burnett... just had to be you.","TWN":"在和伯內特卿進行最後決鬥的地方遇見的人……沒想到，偏偏是你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"기관이 여기를 어떻게 알고 온 거지?","JPN":"機関はどうやってこの場所がわかったのかね？","ENG":"How did the Institution know where to find me?","TWN":"機關是怎麼知道這裡的？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아아, 그거 말이야?","JPN":"ああ、知りたいか？","ENG":"Oh, that?","TWN":"啊啊，這個嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……크악!?","JPN":"……ぐあっ！？","ENG":"...Aargh!","TWN":"……咳？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"이, 이…… 쇠말뚝은……!","JPN":"こ、この……杭は……！","ENG":"Th-these... stakes...!","TWN":"這，這……鐵釘是……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"안뇽~! 또 보네, 고고학부장님?","JPN":"ハロー！　また会えたね、考古学部長さん？","ENG":"Hey there! Good to see you again, Dean of Archeology!","TWN":"你好~！又見面了，考古學教授？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇군. 학회가 기관과 손을 잡았나?","JPN":"なるほど。学会が機関と手を組んだか。","ENG":"I see. So the Society has joined hands with the Institution?","TWN":"原來如此。學會跟機關聯手了？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"맞아! 이럴 때 아니면, 얘들이랑 언제 손을 잡아보겠어?","JPN":"正解！　こいつらと手を組む機会なんてそうそうないからね。","ENG":"Yup! When else would we join forces like this, right?","TWN":"沒錯！如果不是這時候，也就沒機會和他們聯手了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};